/// Map an economic mode to a severity metric (0.0 = healthiest, 1.0 = worst).
fn mode_severity(mode: &autonomic_core::EconomicMode) -> f64 {
    match mode {
        autonomic_core::EconomicMode::Sovereign => 0.0,
        autonomic_core::EconomicMode::Conserving => 0.4,
        autonomic_core::EconomicMode::Hustle => 0.8,
        autonomic_core::EconomicMode::Hibernate => 1.0,
    }
}

/// Apply an Autonomic-specific event to state.
fn apply_autonomic_event(state: &mut HomeostaticState, event: &AutonomicEvent) {
    match event {
        AutonomicEvent::CostCharged {
            amount_micro_credits,
            balance_after,
            ..
        } => {
            state.economic.balance_micro_credits = *balance_after;
            state.economic.lifetime_costs += amount_micro_credits;
            state.economic.last_cost_event_ms = state.last_event_ms;
        }
        AutonomicEvent::EconomicModeChanged { to, .. } => {
            let severity = mode_severity(to);
            let ts_ms = state.last_event_ms;

            // Route through hysteresis gate: only allow escalation (gate active)
            // or relaxation (gate inactive) if the gate permits the transition.
            let gate_active = state.economic.mode_gate.evaluate(severity, ts_ms);

            // If the target mode is more severe, require gate activation.
            // If the target mode is less severe, require gate deactivation.
            let current_severity = mode_severity(&state.economic.mode);
            let allow = if severity > current_severity {
                // Escalating: gate must be active
                gate_active
            } else if severity < current_severity {
                // Relaxing: gate must be inactive
                !gate_active
            } else {
                // Same severity: always allow
                true
            };

            if allow {
                state.economic.mode = *to;
            }
        }
        AutonomicEvent::CreditDeposited {
            amount_micro_credits,
            balance_after,
            ..
        } => {
            state.economic.balance_micro_credits = *balance_after;
            state.economic.lifetime_revenue += amount_micro_credits;
        }
        AutonomicEvent::GatingDecision { .. } => {
            // Informational — no state mutation needed
        }
    }
}

