    #[test]
    fn fold_sequence_produces_deterministic_state() {
        let events = vec![
            EventKind::RunFinished {
                reason: "done".into(),
                total_iterations: 1,
                final_answer: None,
                usage: Some(TokenUsage {
                    prompt_tokens: 100,
                    completion_tokens: 50,
